const cfg = $input.item.json;
const required = [
  'inboxFolderId',
  'processingFolderId',
  'processedFolderId',
  'reviewFolderId',
  'errorFolderId',
  'financialLogSpreadsheetId',
  'financialLogSheetName'
];

const missing = required.filter((key) => {
  const value = cfg[key];
  return value == null || String(value).trim() === '' || String(value).startsWith('REPLACE_WITH_');
});

if (missing.length) {
  throw new Error(`Config placeholders or missing values: ${missing.join(', ')}`);
}

const maxFiles = Number(cfg.maxFilesPerRun ?? 10);
if (!Number.isFinite(maxFiles) || maxFiles < 1 || maxFiles > 100) {
  throw new Error('maxFilesPerRun must be between 1 and 100');
}

const threshold = Number(cfg.confidenceReviewThreshold ?? 0.85);
if (!Number.isFinite(threshold) || threshold <= 0 || threshold >= 1) {
  throw new Error('confidenceReviewThreshold must be between 0 and 1');
}

return [{ json: cfg }];

const items = $input.all().map((i) => i.json || {});
if (!items.length) return [];

items.sort((a, b) => {
  const left = Date.parse(a.createdTime || a.modifiedTime || 0);
  const right = Date.parse(b.createdTime || b.modifiedTime || 0);
  return left - right;
});

return items.map((file) => ({
  json: {
    fileId: file.id,
    fileNameOriginal: file.name || null,
    mimeType: file.mimeType || null,
    createdTime: file.createdTime || null,
    modifiedTime: file.modifiedTime || null
  }
}));

const item = $input.item;

const pick = $('Pick Files').item?.json || {};
const moved = $('Move To 10_PROCESSING').item?.json || {};
const downloaded = $('Download File').item?.json || {};

const stableFileId = item.json.fileId || item.json.id || downloaded.id || moved.id || pick.fileId || null;
if (!stableFileId) {
  throw new Error('Unable to resolve Google Drive file ID for downstream processing.');
}

const extractedRaw = typeof item.json.text === 'string' ? item.json.text : '';
let decodedText = extractedRaw
  .replace(/[^\x09\x0A\x0D\x20-\x7E]/g, ' ')
  .replace(/\s+/g, ' ')
  .trim();

if (!decodedText && item.binary?.data) {
  const buffer = await this.helpers.getBinaryDataBuffer(0, 'data');
  decodedText = buffer
    .toString('utf8')
    .replace(/[^\x09\x0A\x0D\x20-\x7E]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

const maxExtractedChars = 12000;
const extractedText = decodedText.slice(0, maxExtractedChars);
const payloadTruncated = decodedText.length > maxExtractedChars;

const originalName = item.json.fileNameOriginal || moved.name || downloaded.name || pick.fileNameOriginal || null;
const mimeType = item.json.mimeType || moved.mimeType || downloaded.mimeType || pick.mimeType || null;

const aiInput = {
  file_name: originalName,
  mime_type: mimeType,
  payload_truncated: payloadTruncated,
  extracted_text: extractedText,
  extracted_text_chars: extractedText.length
};

return {
  json: {
    fileId: stableFileId,
    fileNameOriginal: originalName,
    mimeType,
    driveFileLink: `https://drive.google.com/file/d/${stableFileId}/view`,
    payloadTruncated,
    aiInput,
    chatInput: JSON.stringify(aiInput)
  },
  binary: item.binary
};

const source = $('Prepare AI Input').item.json;
const cfg = $('Config').first().json;

let raw = $input.item.json.output ?? $input.item.json.response ?? $input.item.json.text ?? '';
if (typeof raw !== 'string') raw = JSON.stringify(raw ?? {});
raw = raw.trim();
if (raw.startsWith('```')) {
  const lines = raw.split('\n');
  if (lines[0].startsWith('```')) lines.shift();
  if (lines.length && lines[lines.length - 1].startsWith('```')) lines.pop();
  raw = lines.join('\n').trim();
}

let parsed;
try {
  parsed = JSON.parse(raw);
} catch (error) {
  parsed = {
    document_type: 'Other',
    vendor: null,
    date_document: null,
    total_amount: null,
    currency: null,
    confidence_score: 0,
    notes: `AI JSON parse failure: ${error.message}`,
    event_summary: null,
    unreadable: true
  };
}

const threshold = Number(cfg.confidenceReviewThreshold ?? 0.85);
const allowedDocTypes = ['Invoice', 'Receipt', 'Bank Statement', 'Other'];
const hasOwn = (obj, key) => Object.prototype.hasOwnProperty.call(obj ?? {}, key);
const requiredExtractionKeys = [
  'document_type',
  'vendor',
  'date_document',
  'total_amount',
  'currency',
  'confidence_score',
  'notes',
  'event_summary',
  'unreadable'
];
const missingExtractionKeys = requiredExtractionKeys.filter((key) => !hasOwn(parsed, key));

const isNonEmptyString = (value) => typeof value === 'string' && value.trim().length > 0;
const isValidDate = (value) => typeof value === 'string' && /^\d{4}-\d{2}-\d{2}$/.test(value);

const docType = allowedDocTypes.includes(parsed.document_type) ? parsed.document_type : 'Other';
let confidence = Number(parsed.confidence_score ?? 0);
if (!Number.isFinite(confidence)) confidence = 0;
confidence = Math.max(0, Math.min(1, confidence));

const parsedAmount = typeof parsed.total_amount === 'number'
  ? parsed.total_amount
  : (parsed.total_amount != null && parsed.total_amount !== '' ? Number(parsed.total_amount) : null);
const amountValid = parsedAmount != null && Number.isFinite(parsedAmount);
const currencyValid = parsed.currency === 'USD';
const vendorValid = isNonEmptyString(parsed.vendor);
const dateValid = isValidDate(parsed.date_document);
const notesValid = isNonEmptyString(parsed.notes);
const eventSummaryValid = isNonEmptyString(parsed.event_summary);
const unreadable = Boolean(parsed.unreadable);

const invalidRequiredValues = [];
if (!allowedDocTypes.includes(parsed.document_type)) invalidRequiredValues.push('document_type');
if (!vendorValid) invalidRequiredValues.push('vendor');
if (!dateValid) invalidRequiredValues.push('date_document');
if (!amountValid) invalidRequiredValues.push('total_amount');
if (!currencyValid) invalidRequiredValues.push('currency');
if (!notesValid) invalidRequiredValues.push('notes');
if (!eventSummaryValid) invalidRequiredValues.push('event_summary');

const lowConfidence = confidence < threshold;
const payloadTruncated = Boolean(source.payloadTruncated);

let route = '20_PROCESSED';
let reviewStatus = 'processed';
const notes = [];

if (missingExtractionKeys.length) {
  notes.push(`Missing extraction keys: ${missingExtractionKeys.join(', ')}`);
}
if (invalidRequiredValues.length) {
  notes.push(`Invalid required values: ${invalidRequiredValues.join(', ')}`);
}

if (unreadable) {
  route = '99_ERROR';
  reviewStatus = 'error';
  notes.push('Unreadable or extraction failure');
} else if (lowConfidence || missingExtractionKeys.length || invalidRequiredValues.length || payloadTruncated) {
  route = '30_REVIEW';
  reviewStatus = 'needs_review';
  if (lowConfidence) notes.push(`Confidence ${confidence.toFixed(2)} below threshold ${threshold}`);
  if (payloadTruncated) notes.push('AI payload truncated before extraction');
}

const now = new Date();
const timestampProcessed = now.toISOString();
const dateFromDoc = dateValid ? parsed.date_document : now.toISOString().slice(0, 10);

const clean = (value, fallback) => {
  const rawValue = (value ?? fallback ?? '').toString().trim();
  const normalized = rawValue
    .replace(/[^a-zA-Z0-9 ]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .replace(/ /g, '_');
  return normalized || fallback;
};

const vendor = clean(parsed.vendor, 'UnknownVendor');
const docTypeName = clean(docType, 'Other');
const original = source.fileNameOriginal || 'document';
const extMatch = original.match(/\.([a-zA-Z0-9]+)$/);
const ext = extMatch
  ? `.${extMatch[1].toLowerCase()}`
  : source.mimeType === 'application/pdf'
    ? '.pdf'
    : '';
const fileNameRenamed = `${dateFromDoc}_${vendor}_${docTypeName}${ext}`;

const routedFolder = route;
const rawAiNotes = typeof parsed.notes === 'string' ? parsed.notes.replace(/\s+/g, ' ').trim() : '';
const rawEventSummary = typeof parsed.event_summary === 'string' ? parsed.event_summary.replace(/\s+/g, ' ').trim() : '';
const fallbackSummary = `Extracted ${docType} for ${vendorValid ? parsed.vendor : 'Unknown vendor'} on ${dateFromDoc}${amountValid ? `, amount ${currencyValid ? parsed.currency : 'USD'} ${parsedAmount.toFixed(2)}` : ''}.`;
const finalEventSummary = (rawEventSummary || rawAiNotes || fallbackSummary).slice(0, 500);
const finalNotes = [...notes, rawAiNotes].filter(Boolean).join(' | ').slice(0, 500) || null;

return {
  json: {
    fileId: source.fileId,
    fileNameOriginal: source.fileNameOriginal,
    fileNameRenamed,
    documentType: docType,
    vendor: vendorValid ? vendor : 'UnknownVendor',
    dateDocument: dateFromDoc,
    totalAmount: amountValid ? parsedAmount : null,
    currency: currencyValid ? parsed.currency : 'USD',
    confidenceScore: confidence,
    reviewStatus,
    routedFolder,
    driveFileLink: source.driveFileLink,
    notes: finalNotes,
    eventSummary: finalEventSummary,
    timestampProcessed
  },
  binary: $('Prepare AI Input').item.binary
};

const item = $input.item.json || {};
const cfg = $('Config').first().json;
const parseNode = $('Parse And Normalize').item?.json || {};
const renameNode = $('Rename File').item?.json || {};

const stableFileId = item.fileId || item.id || parseNode.fileId || renameNode.id || null;
if (!stableFileId) {
  throw new Error('Unable to resolve file ID before terminal folder move.');
}

const routedFolder = item.routedFolder || parseNode.routedFolder || '20_PROCESSED';
let targetFolderId = cfg.processedFolderId;
if (routedFolder === '30_REVIEW') targetFolderId = cfg.reviewFolderId;
if (routedFolder === '99_ERROR') targetFolderId = cfg.errorFolderId;

if (!targetFolderId || String(targetFolderId).startsWith('REPLACE_WITH_')) {
  throw new Error(`Missing target folder for route ${routedFolder}`);
}

return {
  json: {
    ...parseNode,
    ...item,
    fileId: stableFileId,
    routedFolder,
    targetFolderId
  }
};
